141→internal class OptionalFormatStructure<in T>(
142→    val onZero: String,
143→    val format: FormatStructure<T>,
144→) : NonConcatenatedFormatStructure<T> {
145→    override fun toString(): String = "Optional($onZero, $format)"
146→
147→    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148→        PropertyWithDefault.fromField(field)
149→    }
150→
151→    override fun equals(other: Any?): Boolean =
152→        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153→
154→    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155→
156→    override fun parser(): ParserStructure<T> = ParserStructure(
157→        operations = emptyList(),
158→        followedBy = listOf(
159→            format.parser(),
160→            listOf(
161→                ConstantFormatStructure<T>(onZero).parser(),
162→                ParserStructure(
163→                    listOf(
164→                        UnconditionalModification {
165→                            for (field in fields) {
166→                                field.assignDefault(it)
167→                            }
168→                        }
169→                    ),
170→                    emptyList()
171→                )
172→            ).concat()
173→        )
174→    )
175→
176→    override fun formatter(): FormatterStructure<T> {
177→        val formatter = format.formatter()
178→        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
179→        return ConditionalFormatter(
180→            listOf(
181→                predicate::test to ConstantStringFormatterStructure(onZero),
182→                Truth::test to formatter
183→            )
184→        )
185→    }
186→
187→    private class PropertyWithDefault<in T, E> private constructor(
188→        private val accessor: Accessor<T, E>,
189→        private val defaultValue: E
190→    ) {
191→        companion object {
192→            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
193→                val default = field.defaultValue
194→                require(default != null) {
195→                    "The field '${field.name}' does not define a default value"
196→                }
197→                return PropertyWithDefault(field.accessor, default)
198→            }
199→        }
200→
201→        inline fun assignDefault(target: T) {
202→            accessor.trySetWithoutReassigning(target, defaultValue)
203→        }
204→
205→        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
206→    }
207→}
