package kotlinx.datetime.test.format

import kotlinx.datetime.DateTimeFormatException
import kotlinx.datetime.LocalDate
import kotlinx.datetime.LocalTime
import kotlinx.datetime.format.FormatStringsInDatetimeFormats
import kotlinx.datetime.format.char
import kotlinx.datetime.format.hour
import kotlinx.datetime.format.amPmMarker
import kotlin.test.Test
import kotlin.test.assertContains
import kotlin.test.assertFailsWith
import kotlin.test.assertFalse

class ErrorMessageImprovementsTest {

    @Test
    fun testInputIncludedInPostParseValidationErrors() {
        val input = "2023-02-30"
        val e = assertFailsWith<DateTimeFormatException> { LocalDate.Formats.ISO.parse(input) }
        assertContains(e.message!!, input)
        assertContains(e.message!!, "Failed to parse value from")
    }

    @Test
    fun testInputIncludedInInconsistentHourAndAmPmErrors() {
        val format = LocalTime.Format {
            hour()
            char(' ')
            amPmMarker()
        }
        val input = "23 AM"
        val e = assertFailsWith<DateTimeFormatException> { format.parse(input) }
        assertContains(e.message!!, input)
        assertContains(e.message!!, "Inconsistent hour and the AM/PM marker")
    }

    @Test
    fun testExpectedOneOfIsLowerCasedInParseErrors() {
        val format = LocalTime.Format {
            amPmMarker()
        }
        val e = assertFailsWith<DateTimeFormatException> { format.parse("XX") }
        val causeMessage = e.cause?.message
        assertContains(causeMessage ?: "", "Position 0")
        assertContains(causeMessage ?: "", "Expected one of")
        assertFalse((causeMessage ?: "").contains("Expected One of"))
    }
}
